xpath.script:
if ('serviceWorker' in navigator) {
    window.addEventListener('load', function() {
        navigator.serviceWorker.register('/van_sales_pharma/static/service-worker.js').then(function(registration) {
            console.log('Van Sales ServiceWorker registration successful with scope: ', registration.scope);
        }, function(err) {
            console.log('Van Sales ServiceWorker registration failed: ', err);
        });
    });
}
